'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { Shield, User, Lock, Mail, ChevronLeft, LogIn } from 'lucide-react';
import { useStore } from '@/store/useStore';
import { apiClient } from '@/lib/api-client';

export default function AuthPage() {
  const router = useRouter();
  const { user, setUser } = useStore();
  const [role, setRole] = useState<'admin' | 'employee'>('admin');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Auto-redirect if already logged in
  useEffect(() => {
    if (user) {
      router.push('/dashboard');
    }
  }, [user, router]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !password) {
      setErrorMsg('Please enter both email and password');
      return;
    }

    setLoading(true);
    setErrorMsg(null);

    try {
      const res = await apiClient.post('/api/auth/login', { email, password });
      if (res.success) {
        setUser(res.user);
        router.push('/dashboard');
      } else {
        setErrorMsg(res.message || 'Invalid email or password');
      }
    } catch (err: any) {
      setErrorMsg(err.message || 'Connection error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const fillCredentials = (type: 'admin' | 'employee') => {
    if (type === 'admin') {
      setEmail('man@pps.com');
      setPassword('MAN@1234');
      setRole('admin');
    } else {
      setEmail('rahul@pps.com');
      setPassword('man@1234');
      setRole('employee');
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 dark:bg-slate-950 font-sans text-slate-800 dark:text-slate-200">
      
      {/* 1. Left Side Decorative Image Panel (Desktop only) */}
      <div className="hidden lg:flex lg:w-1/2 bg-blue-600 dark:bg-blue-950 items-center justify-center p-12 relative overflow-hidden">
        {/* Abstract decorative SVG vector */}
        <div className="absolute inset-0 bg-gradient-to-br from-blue-600/90 to-indigo-900/90 z-0"></div>
        <div className="absolute -top-40 -left-40 w-96 h-96 bg-white/10 rounded-full blur-3xl"></div>
        <div className="absolute -bottom-40 -right-40 w-96 h-96 bg-indigo-500/20 rounded-full blur-3xl"></div>
        
        <div className="relative z-10 max-w-md text-white space-y-6">
          <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-white text-blue-600 font-black text-xl shadow-lg">
            PPS
          </div>
          <div className="space-y-3">
            <h1 className="text-3xl font-extrabold tracking-tight">Simplify Your Payroll</h1>
            <p className="text-blue-100 text-sm leading-relaxed font-medium">
              Streamline salary processing, automate tax calculations, and manage employee payments with our comprehensive payroll solution.
            </p>
          </div>
          <div className="pt-6 border-t border-white/10 grid grid-cols-2 gap-4 text-xs font-semibold text-blue-200">
            <div>
              <p className="text-white font-bold">100% Secure</p>
              <p className="mt-1 font-medium text-[10px]">Bank-grade JWT encryption</p>
            </div>
            <div>
              <p className="text-white font-bold">Compliant</p>
              <p className="mt-1 font-medium text-[10px]">Tax calculations made easy</p>
            </div>
          </div>
        </div>
      </div>

      {/* 2. Right Side Form Panel */}
      <div className="w-full lg:w-1/2 flex items-center justify-center p-6 sm:p-12 relative">
        <div className="w-full max-w-md space-y-8 animate-in fade-in duration-500">
          
          {/* Brand Header */}
          <div className="flex flex-col items-center lg:items-start text-center lg:text-left">
            <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-blue-600 text-white font-black text-sm shadow-md shadow-blue-500/10 mb-4 lg:hidden">
              PPS
            </div>
            <h2 className="text-2xl font-black tracking-tight text-slate-900 dark:text-white">
              {role === 'admin' ? 'Admin Sign In' : 'Employee Sign In'}
            </h2>
            <p className="text-xs text-slate-500 dark:text-slate-400 font-medium mt-1">
              Welcome back! Please enter your details below.
            </p>
          </div>

          {/* Role selector tab buttons */}
          <div className="grid grid-cols-2 gap-2 p-1 bg-slate-100 dark:bg-slate-900 rounded-xl">
            <button
              onClick={() => { setRole('admin'); setErrorMsg(null); }}
              className={`flex items-center justify-center gap-2 py-2 text-xs font-bold rounded-lg transition-all
                ${role === 'admin'
                  ? 'bg-white dark:bg-slate-800 text-blue-600 shadow-sm'
                  : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'
                }
              `}
            >
              <Shield size={14} />
              Admin
            </button>
            <button
              onClick={() => { setRole('employee'); setErrorMsg(null); }}
              className={`flex items-center justify-center gap-2 py-2 text-xs font-bold rounded-lg transition-all
                ${role === 'employee'
                  ? 'bg-white dark:bg-slate-800 text-blue-600 shadow-sm'
                  : 'text-slate-500 dark:text-slate-400 hover:text-slate-800'
                }
              `}
            >
              <User size={14} />
              Employee
            </button>
          </div>

          {/* Alert Error Box */}
          {errorMsg && (
            <div className="p-3 text-xs font-semibold rounded-xl bg-red-50 dark:bg-red-950/20 text-red-600 dark:text-red-400 border border-red-200/50 dark:border-red-900/30">
              {errorMsg}
            </div>
          )}

          {/* Form */}
          <form className="space-y-4" onSubmit={handleSubmit}>
            {/* Email */}
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-600 dark:text-slate-400 uppercase tracking-wider">
                Email Address
              </label>
              <div className="relative">
                <Mail size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400" />
                <input
                  type="email"
                  required
                  placeholder={role === 'admin' ? 'man@pps.com' : 'rahul@pps.com'}
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full h-11 rounded-xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 pl-10 pr-4 text-xs font-medium text-slate-900 dark:text-white placeholder-slate-400 focus:border-blue-500 focus:outline-none transition-colors"
                />
              </div>
            </div>

            {/* Password */}
            <div className="space-y-1">
              <div className="flex items-center justify-between">
                <label className="text-xs font-bold text-slate-600 dark:text-slate-400 uppercase tracking-wider">
                  Password
                </label>
                <a href="#" className="text-xs font-semibold text-blue-600 hover:text-blue-500 transition-colors">
                  Forgot Password?
                </a>
              </div>
              <div className="relative">
                <Lock size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400" />
                <input
                  type="password"
                  required
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full h-11 rounded-xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 pl-10 pr-4 text-xs font-medium text-slate-900 dark:text-white placeholder-slate-400 focus:border-blue-500 focus:outline-none transition-colors"
                />
              </div>
            </div>

            {/* Remember Me */}
            <div className="flex items-center">
              <input
                id="remember"
                type="checkbox"
                checked={rememberMe}
                onChange={(e) => setRememberMe(e.target.checked)}
                className="h-4 w-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
              />
              <label htmlFor="remember" className="ml-2 text-xs font-semibold text-slate-500 dark:text-slate-400 select-none cursor-pointer">
                Remember Me
              </label>
            </div>

            {/* Submit Button */}
            <button
              type="submit"
              disabled={loading}
              className="flex w-full h-11 items-center justify-center gap-2 rounded-xl bg-blue-600 hover:bg-blue-500 text-white font-bold text-sm shadow-md shadow-blue-600/10 hover:shadow-lg hover:shadow-blue-600/15 active:scale-99 transition-all disabled:opacity-50"
            >
              {loading ? (
                <div className="h-5 w-5 animate-spin rounded-full border-2 border-white border-t-transparent"></div>
              ) : (
                <>
                  <LogIn size={16} />
                  Sign In
                </>
              )}
            </button>
          </form>

          {/* Quick Demo Login Credentials Box */}
          <div className="p-4 rounded-xl border border-blue-100 dark:border-blue-900/30 bg-blue-50/50 dark:bg-blue-950/10 space-y-2">
            <span className="text-[10px] font-bold text-blue-600 dark:text-blue-400 uppercase tracking-wider block">
              🔑 Quick Demo Credentials
            </span>
            <div className="grid grid-cols-2 gap-2.5">
              <button
                onClick={() => fillCredentials('admin')}
                className="p-2 text-left rounded-lg bg-white dark:bg-slate-900 hover:bg-blue-50 dark:hover:bg-slate-800/80 border border-slate-100 dark:border-slate-800 text-[10px] leading-relaxed transition-all"
              >
                <span className="font-bold text-slate-700 dark:text-slate-300 block">Administrator</span>
                <span className="text-slate-500 dark:text-slate-400">man@pps.com</span>
                <span className="text-slate-400 block mt-0.5">Pass: MAN@1234</span>
              </button>
              <button
                onClick={() => fillCredentials('employee')}
                className="p-2 text-left rounded-lg bg-white dark:bg-slate-900 hover:bg-blue-50 dark:hover:bg-slate-800/80 border border-slate-100 dark:border-slate-800 text-[10px] leading-relaxed transition-all"
              >
                <span className="font-bold text-slate-700 dark:text-slate-300 block">Employee (Rahul)</span>
                <span className="text-slate-500 dark:text-slate-400">rahul@pps.com</span>
                <span className="text-slate-400 block mt-0.5">Pass: man@1234</span>
              </button>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}
